code = """import json
import pandas as pd

# Access the results using locals()
casehistory_data = locals()['var_functions.query_db:12']
case_data = locals()['var_functions.query_db:10']

# Convert to DataFrames
ch_df = pd.DataFrame(casehistory_data)
case_df = pd.DataFrame(case_data)

# Clean ID fields by removing leading #
def clean_id(id_val):
    if pd.isna(id_val):
        return id_val
    if isinstance(id_val, str) and id_val.startswith('#'):
        return id_val[1:]
    return id_val

# Clean casehistory data
for col in ['caseid__c', 'oldvalue__c', 'newvalue__c']:
    ch_df[col] = ch_df[col].apply(clean_id)

# Clean case data
case_df['id'] = case_df['id'].apply(clean_id)
case_df['ownerid'] = case_df['ownerid'].apply(clean_id)

# Identify cases with transfers (Owner Assignment where oldvalue is not None or 'None')
transfers = ch_df[
    (ch_df['field__c'] == 'Owner Assignment') & 
    (ch_df['oldvalue__c'].notna()) & 
    (ch_df['oldvalue__c'] != 'None') &
    (ch_df['newvalue__c'].notna()) & 
    (ch_df['newvalue__c'] != 'None')
]

# Count transfers per agent (the agent who transferred = oldvalue__c)
transfer_counts = transfers.groupby('oldvalue__c').size().reset_index(name='transfer_count')

# Get list of all agents with cases
agents_with_cases = set(case_df['ownerid'].unique())

# Filter transfer counts to only include agents who have cases
valid_agents = transfer_counts[transfer_counts['oldvalue__c'].isin(agents_with_cases)]

# Add agents with cases but no transfers
agents_with_zero_transfers = list(agents_with_cases - set(valid_agents['oldvalue__c'].unique()))

if agents_with_zero_transfers:
    zero_transfers = pd.DataFrame({
        'oldvalue__c': agents_with_zero_transfers,
        'transfer_count': [0] * len(agents_with_zero_transfers)
    })
    all_agents = pd.concat([valid_agents, zero_transfers], ignore_index=True)
else:
    all_agents = valid_agents

# Find agent with fewest transfers
fewest_transfers_agent = all_agents.nsmallest(1, 'transfer_count')
agent_id = fewest_transfers_agent.iloc[0]['oldvalue__c']

result = agent_id

print('__RESULT__:')
print(json.dumps(result))"""

